{
  "summary": "La integración actual tiene incompatibilidades en evento, payload, firma y políticas; requiere ajustes para alinear con Documento 2.",
  "current_mismatches": [
    {
      "area": "event_name",
      "severity": "medium",
      "issue": "Código usa 'document_uploaded'; contrato espera 'document.uploaded'.",
      "required_change": "Cambiar constante AUDITAPATRON_ENGINE_EVENT a 'document.uploaded'."
    },
    {
      "area": "payload_structure",
      "severity": "high",
      "issue": "Payload incluye campos extras (payloadVersion, source, tenantId, traceId, fileKey, idempotencyKey, contracts) y falta fileSizeBytes opcional; contrato espera estructura plana específica sin extras.",
      "required_change": "Reconstruir payload en buildAuditaPatronEnginePayload para incluir solo campos requeridos/opcionales de Documento 2, eliminando extras y nested contracts."
    },
    {
      "area": "signature_calculation",
      "severity": "high",
      "issue": "Firma calcula HMAC_SHA256 solo sobre body; contrato requiere HMAC_SHA256 sobre timestamp + '.' + body.",
      "required_change": "Modificar buildAuditaPatronEngineSignature para usar input = timestamp + '.' + body, donde timestamp es dispatchedAt."
    },
    {
      "area": "signature_format",
      "severity": "medium",
      "issue": "Firma prefijada con 'hmac-sha256:'; contrato no especifica prefijo, solo hex digest.",
      "required_change": "Eliminar prefijo en buildAuditaPatronEngineSignature, enviar solo el hex digest en header X-AuditaPatron-Signature."
    },
    {
      "area": "headers",
      "severity": "medium",
      "issue": "Envía headers extras (X-AuditaPatron-Event, X-AuditaPatron-Payload-Version, X-AuditaPatron-Idempotency-Key); contrato implica solo signature y timestamp.",
      "required_change": "Limitar headers a Content-Type, X-AuditaPatron-Signature y X-AuditaPatron-Timestamp en sendDocumentToAuditaPatronEngine."
    },
    {
      "area": "retry_policy",
      "severity": "high",
      "issue": "No implementa reintentos; contrato requiere backoff exponencial (30s, 60s, 120s, max 3) solo en 5xx, no en 4xx.",
      "required_change": "Agregar lógica de reintentos en sendDocumentToAuditaPatronEngine con backoff y límite, condicional a HTTP 5xx."
    },
    {
      "area": "idempotency",
      "severity": "low",
      "issue": "Usa idempotencyKey como document_id:sha256; contrato deduplica por sha256 solo.",
      "required_change": "Eliminar envío de idempotencyKey, confiar en deduplicación por sha256 del receptor."
    },
    {
      "area": "response_handling",
      "severity": "medium",
      "issue": "Considera !response.ok como failure; contrato usa 200 para duplicados y 201 para nuevos, ambos success.",
      "required_change": "Ajustar chequeo para tratar 200 y 201 como 'sent', manejar errores específicos como 401, 400, etc."
    },
    {
      "area": "test_mode",
      "severity": "low",
      "issue": "No soporta modo test (documentId inicia con test_); contrato lo valida.",
      "required_change": "Agregar soporte opcional para prefijar documentId con 'test_' en entornos de prueba."
    }
  ],
  "target_contract": {
    "event": "document.uploaded",
    "required_fields": ["event", "documentId", "sourceUserId", "docType", "fileUrl", "sha256", "mimeType", "uploadedAt"],
    "optional_fields": ["fileSizeBytes", "auditId", "caseId", "metadata"],
    "signature_algorithm": "HMAC_SHA256",
    "signature_input": "timestamp + '.' + body",
    "required_headers": ["X-AuditaPatron-Signature", "X-AuditaPatron-Timestamp"],
    "retry_policy": "Reintentar solo en 5xx con backoff 30s -> 60s -> 120s, máximo 3 intentos; no reintentar 4xx",
    "idempotency_rule": "Deduplicación por sha256; reintentos seguros"
  },
  "doc_type_mapping": [
    {
      "current_internal_type": "payroll_receipt",
      "target_doc_type": "recibo_nomina",
      "notes": "Mapeo directo basado en ejemplo de prueba; asumir equivalencia semántica."
    },
    {
      "current_internal_type": "imss_certificate",
      "target_doc_type": "constancia_imss",
      "notes": "Mapeo propuesto para certificados IMSS."
    },
    {
      "current_internal_type": "infonavit_certificate",
      "target_doc_type": "constancia_infonavit",
      "notes": "Mapeo propuesto para certificados INFONAVIT."
    },
    {
      "current_internal_type": "employment_contract",
      "target_doc_type": "contrato_laboral",
      "notes": "Mapeo propuesto para contratos laborales."
    },
    {
      "current_internal_type": "cfdi_payroll",
      "target_doc_type": "cfdi_nomina",
      "notes": "Mapeo propuesto para CFDI de nómina."
    },
    {
      "current_internal_type": "compliance_opinion",
      "target_doc_type": "opinion_cumplimiento",
      "notes": "Mapeo propuesto para opiniones de cumplimiento."
    }
  ],
  "implementation_sequence": [
    "Actualizar nombre de evento a 'document.uploaded'.",
    "Simplificar estructura de payload para coincidir con campos requeridos/opcionales.",
    "Corregir cálculo y formato de firma HMAC.",
    "Ajustar headers enviados a solo los requeridos.",
    "Implementar mapeo de tipos documentales en buildAuditaPatronEnginePayload.",
    "Agregar lógica de reintentos con backoff en sendDocumentToAuditaPatronEngine.",
    "Actualizar manejo de respuestas para 200/201 como éxito.",
    "Agregar soporte para modo test.",
    "Actualizar pruebas para validar contra contrato de Documento 2.",
    "Desplegar y monitorear integración."
  ],
  "risks": [
    "Pérdida de datos al eliminar campos extras como contracts, potencialmente afectando trazabilidad.",
    "Fallas de seguridad si firma no se alinea, causando rechazos 401.",
    "Sobrecarga en receptor si reintentos no se implementan correctamente.",
    "Incompatibilidades en producción si mapeo de docType es incorrecto.",
    "Falta de manejo de errores específicos (e.g., 429 rate_limit) podría causar loops."
  ],
  "go_no_go": "go_with_changes"
}
